    за (int j=1; j<=p.length(); j++) {
        ако (p.charAt(j-1)=='*') {
            dp[0][j] = dp[0][j-2];
        }
    }
    за (int i=1; i<=s.length(); i++) {
        за (int j=1; j<=p.length(); j++) {
            ако (p.charAt(j-1)=='.' || p.charAt(j-1)==s.charAt(i-1)) {
                dp[i][j] = dp[i-1][j-1];
            } else if (p.charAt(j-1)=='*') {
                dp[i][j] = dp[i][j-2];
                if (p.charAt(j-2)=='.' || p.charAt(j-2)==s.charAt(i-1)) {
                    dp[i][j] |= dp[i-1][j];
                }
            }
        }
    }
    врати dp[s.length()][p.length()];
}
